import { useEffect, useState } from 'react';
import { AdminService } from '../../../services/api';
import { Trash2, Layers, Hash, Loader2, Upload } from 'lucide-react';
import { AdminTaxonomyForm } from './AdminTaxonomyForm'; 
import toast from 'react-hot-toast';

export const AdminTaxonomy = () => {
  const [data, setData] = useState<any>({ themes: [], tags: [] });
  const [fetching, setFetching] = useState(true);

  const fetchTaxonomy = async () => {
    try {
      const res: any = await AdminService.getAllTaxonomy();
      setData(res.data?.data || { themes: [], tags: [] });
    } catch (err) {
      toast.error("Taxonomy Sync Failed");
    } finally {
      setFetching(false);
    }
  };

  useEffect(() => { fetchTaxonomy(); }, []);

  // Handle Excel Import for Themes or Tags
  const handleExcelImport = async (type: 'theme' | 'tag', file: File) => {
    try {
      await AdminService.importData(type, file);
      toast.success(`${type}s imported successfully`);
      fetchTaxonomy();
    } catch (err) {
      toast.error(`Import failed for ${type}s`);
    }
  };

  const handleDelete = async (id: string, type: 'theme' | 'tag') => {
    if (!window.confirm(`Permanently remove this ${type}?`)) return;
    try {
      await AdminService.deleteTaxonomy(id, type);
      toast.success("Entry Purged");
      fetchTaxonomy();
    } catch (err) {
      toast.error("Delete failed");
    }
  };

  if (fetching) return (
    <div className="h-96 flex flex-col items-center justify-center text-primary">
      <Loader2 className="animate-spin mb-4" size={32} />
      <p className="text-[10px] font-black uppercase tracking-[0.2em]">Synchronizing Taxonomy...</p>
    </div>
  );

  return (
    <div className="p-8 space-y-10 animate-in fade-in duration-700">
      <div className="flex justify-between items-end">
        <div>
          <h1 className="text-4xl font-black uppercase italic text-white">
            Taxonomy <span className="text-primary">Control</span>
          </h1>
          <p className="text-gray-500 font-bold uppercase text-[10px] tracking-[0.3em] mt-1">Classification Management</p>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-10">
        
        {/* --- THEMES SECTION --- */}
        <div className="space-y-6">
          <div className="flex justify-between items-center bg-white/5 p-4 rounded-2xl border border-white/5">
            <div className="flex items-center gap-2">
              <Layers className="text-primary" size={18} />
              <h2 className="text-white font-black uppercase text-xs tracking-widest italic">Global Themes</h2>
            </div>
            {/* Excel Import Button for Themes */}
            <label className="cursor-pointer group flex items-center gap-2 px-3 py-2 bg-white/5 rounded-xl border border-white/10 hover:border-primary transition-all">
              <Upload size={14} className="text-gray-500 group-hover:text-primary" />
              <span className="text-[9px] font-black uppercase text-gray-500 group-hover:text-white">Excel Import</span>
              <input type="file" className="hidden" onChange={(e) => e.target.files?.[0] && handleExcelImport('theme', e.target.files[0])} />
            </label>
          </div>
          
          <AdminTaxonomyForm type="theme" onSuccess={fetchTaxonomy} />
          
          <div className="space-y-2 max-h-[400px] overflow-y-auto pr-2 custom-scrollbar">
            {data.themes.map((t: any) => (
              <div key={t._id} className="p-4 bg-[#0f0f0f] rounded-2xl border border-white/5 flex justify-between items-center group">
                <div className="flex flex-col">
                  <span className="text-[8px] font-black text-primary uppercase">{t.Theme_ID}</span>
                  <span className="text-xs font-bold uppercase text-white italic">{t.Theme_Name}</span>
                </div>
                <button onClick={() => handleDelete(t._id, 'theme')} className="p-2 text-gray-600 hover:text-red-500">
                  <Trash2 size={14} />
                </button>
              </div>
            ))}
          </div>
        </div>

        {/* --- TAGS SECTION --- */}
        <div className="space-y-6">
          <div className="flex justify-between items-center bg-white/5 p-4 rounded-2xl border border-white/5">
            <div className="flex items-center gap-2">
              <Hash className="text-primary" size={18} />
              <h2 className="text-white font-black uppercase text-xs tracking-widest italic">Search Tags</h2>
            </div>
            {/* Excel Import Button for Tags */}
            <label className="cursor-pointer group flex items-center gap-2 px-3 py-2 bg-white/5 rounded-xl border border-white/10 hover:border-primary transition-all">
              <Upload size={14} className="text-gray-500 group-hover:text-primary" />
              <span className="text-[9px] font-black uppercase text-gray-500 group-hover:text-white">Excel Import</span>
              <input type="file" className="hidden" onChange={(e) => e.target.files?.[0] && handleExcelImport('tag', e.target.files[0])} />
            </label>
          </div>

          <AdminTaxonomyForm type="tag" onSuccess={fetchTaxonomy} />
          
          <div className="flex flex-wrap gap-2">
            {data.tags.map((t: any) => (
              <div key={t._id} className="group flex items-center bg-white/5 border border-white/10 rounded-xl px-4 py-2 hover:border-primary/50 transition-all">
                <div className="flex flex-col">
                  <span className="text-[7px] font-black text-primary uppercase leading-none mb-1">{t.Tag_ID}</span>
                  <span className="text-[10px] font-black uppercase text-gray-300">#{t.Tag_Name}</span>
                </div>
                <button onClick={() => handleDelete(t._id, 'tag')} className="ml-3 p-1 text-gray-600 hover:text-red-500 opacity-0 group-hover:opacity-100 transition-all">
                  <Trash2 size={12} />
                </button>
              </div>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
};
